import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"66. Pre Adoption Leave","description":"","frontmatter":{"title":"66. Pre Adoption Leave","eba":"Doctors in Training 2022-2026","topics":["leave","parental-leave","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/66-pre-adoption-leave.md","filePath":"ebas/doctors-in-training/leave/66-pre-adoption-leave.md"}'),n={name:"ebas/doctors-in-training/leave/66-pre-adoption-leave.md"};function i(p,e,s,d,l,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_66-pre-adoption-leave" tabindex="-1">66. Pre Adoption Leave <a class="header-anchor" href="#_66-pre-adoption-leave" aria-label="Permalink to &quot;66. Pre Adoption Leave&quot;">​</a></h1><p><strong>66.1</strong> A Doctor seeking to adopt a child is, on the production of satisfactory evidence if required, entitled to unpaid leave for the purpose of attending any interviews or examinations necessary to the adoption procedure.</p><p><strong>66.2</strong> The Doctor and the Health Service may agree on the length of the unpaid leave.</p><p><strong>66.3</strong> Where agreement cannot be reached, the Doctor is entitled to take up to two days unpaid leave.</p><p><strong>66.4</strong> Where paid leave is available to the Doctor, the Health Service may require the Doctor to take such leave instead.</p><p>Plain language terms: adoption leave.</p>',6)])])}const _=t(n,[["render",i]]);export{h as __pageData,_ as default};
